        /// If the CurrentReading is between UpperThresholdCritical and UpperThresholdFatal, then the CurrentState is Critical.<br/>
        /// <br/>
        /// cimtype: sint32<br/>
        /// <br/>
        /// units: milliamps<br/>
        /// <br/>
        /// </summary>
        public int UpperThresholdCritical { get; set; }
        /// <summary>
